        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Memoization map: mask -> max palindrome length
    unordered_map<long long, long long> memo;

    // Helper function to perform DFS
    auto dfs = [&](long long node, long long mask, long long start, long long end) -> long long {
